// tsconfig.json nümunəsi
{
  "compilerOptions": {
    "target": "ES6",
    "module": "CommonJS",
    "outDir": "./dist",
    "rootDir": "./src",
    "strict": true,
    "esModuleInterop": true,
    "skipLibCheck": true
  }
}

// 1. target və module
// target: ES6, module: CommonJS
interface User {
  name: string;
}
function greet(user: User): string {
  return "Hello, " + user.name;
}
const user: User = { name: "Alice" };
console.log(greet(user)); // Çıxış: Hello, Alice

// 2. strict rejimi
// strict: true ilə null yoxlaması tələb olunur
let username: string | null = "Bob";
// let invalid: string = null; // Səhv: null string tipinə uyğun deyil
if (username !== null) {
  console.log(username.toUpperCase()); // Çıxış: BOB
}

// 3. esModuleInterop
// esModuleInterop ilə CommonJS modulları ilə işləmək asanlaşır
import * as fs from "fs"; // CommonJS modulu kimi idxal
// esModuleInterop olmadan: const fs = require("fs");

// 4. outDir və rootDir
// src qovluğundakı TypeScript faylları dist qovluğuna kompilyasiya olunur
class Product {
  name: string;
  constructor(name: string) {
    this.name = name;
  }
}
const product = new Product("Laptop");
console.log(product.name); // Çıxış: Laptop

// tsconfig.json: {"compilerOptions": {"target": "ES6", "module": "CommonJS", "outDir": "./dist", "rootDir": "./src", "strict": true}}

interface Product {
  id: string;
  name: string;
  price: number | null;
}

class Store {
  products: Product[] = [];

  addProduct(id: string, name: string, price: number | null): Product[] {
    if (price === null) {
      console.log("Warning: Price is null");
      return this.products;
    }
    const product: Product = { id, name, price };
    this.products = [...this.products, product];
    return this.products;
  }
}

const store = new Store();
console.log(store.addProduct("P001", "Laptop", 999)); // Çıxış: [{ id: "P001", name: "Laptop", price: 999 }]
console.log(store.addProduct("P002", "Phone", null)); // Çıxış: Warning: Price is null
// Çıxış: [{ id: "P001", name: "Laptop", price: 999 }]

